class Solution:
    def minStartingIndex(self, s, pattern):
        n, m = len(s), len(pattern)
        for i in range(n - m + 1):
            diff = sum(1 for a, b in zip(s[i:i + m], pattern) if a != b)
            if diff <= 1:
                return i
        return -1

