class Solution:
    def minStartingIndex(self, s, pattern):
        def z_function(st):
            L = len(st)
            z = [0] * L
            l, r = 0, 0
            for i in range(1, L):
                if i < r:
                    z[i] = min(r - i, z[i - l])
                while i + z[i] < L and st[z[i]] == st[i + z[i]]:
                    z[i] += 1
                if i + z[i] > r:
                    l, r = i, i + z[i]
            return z

        n, m = len(s), len(pattern)
        if m > n:
            return -1
        comb1 = pattern + '\x00' + s
        z1 = z_function(comb1)
        front = [min(m, z1[m + 1 + i]) for i in range(n)]

        rev_s = s[::-1]
        rev_p = pattern[::-1]
        comb2 = rev_p + '\x00' + rev_s
        z2 = z_function(comb2)
        back = [0] * n
        for j in range(n):
            k = n - 1 - j
            back[j] = min(m, z2[m + 1 + k])

        for i in range(n - m + 1):
            f = front[i]
            if f == m:
                return i
            b = back[i + m - 1]
            if f + b >= m - 1:
                return i
        return -1

