var minStartingIndex = function(s, pattern) {
    function zFunction(str) {
        const L = str.length;
        const z = new Array(L).fill(0);
        let l = 0, r = 0;
        for (let i = 1; i < L; i++) {
            if (i < r) z[i] = Math.min(r - i, z[i - l]);
            while (i + z[i] < L && str[z[i]] === str[i + z[i]]) z[i]++;
            if (i + z[i] > r) { l = i; r = i + z[i]; }
        }
        return z;
    }
    const n = s.length, m = pattern.length;
    if (m > n) return -1;
    const comb1 = pattern + '\u0000' + s;
    const z1 = zFunction(comb1);
    const front = new Array(n).fill(0);
    for (let i = 0; i < n; i++) front[i] = Math.min(m, z1[m + 1 + i]);

    const revS = s.split('').reverse().join('');
    const revP = pattern.split('').reverse().join('');
    const comb2 = revP + '\u0000' + revS;
    const z2 = zFunction(comb2);
    const back = new Array(n).fill(0);
    for (let j = 0; j < n; j++) {
        const k = n - 1 - j;
        back[j] = Math.min(m, z2[m + 1 + k]);
    }

    for (let i = 0; i <= n - m; i++) {
        const f = front[i];
        if (f === m) return i;
        const b = back[i + m - 1];
        if (f + b >= m - 1) return i;
    }
    return -1;
};
